query:
-- Verificar colunas na tabela clientes
SELECT column_name, data_type FROM information_schema.columns 
WHERE table_name = 'clientes' AND column_name LIKE '%created%';

-- Verificar colunas na tabela contratos
SELECT column_name, data_type FROM information_schema.columns 
WHERE table_name = 'contratos' AND column_name LIKE '%created%';

-- Verificar se a tabela vendas existe
SELECT table_name FROM information_schema.tables 
WHERE table_name = 'vendas';

